sql:
SELECT SUM(cost) AS total_treatment_cost
FROM treatments
WHERE treatment_date BETWEEN '2023-01-01' AND '2023-12-31';

SELECT COUNT(billing_id) AS unpaid_invoices_count
FROM billing
WHERE patient_id = 123 AND status = 'unpaid';

SELECT treatment_id, treatment_date
FROM treatments
ORDER BY treatment_date DESC;

external_knowledge:
- 'heaviest spenders' refers to patients who have the highest overall cost of treatments; 
- 'medical journeys' metaphorically represents the treatments patients have undergone; 
- 'wise guardians' is a metaphorical term for the doctors providing the treatments.
